function [imgC,missI] = fDnnImg(imgPathC,sNmbS,camClb,bgImgC,lPass,vgntC,x,c2c)%% Return processed images for Dnn magspec%% [imgC,missI] = fBellaImgV01(imgPathC,sNmbS,camClb,imgC,bgImgC,lPass,anglC)%% imgC: cell of processed images% missI: missing image info%% imgPathC: cell of image path% sNmbS: shot number string% camClb: structure of calibration for bella magspec cameras%   .fov: field of view [mm]%   .yOffset: y offset for roi [pixel]%   .height: height of image [pixel]%   .xOffset: x offset for roi [pixel]%   .width: width of image [pixel]%   .leftPos: left position of image [mm]%   .yCnter: y center pixel%   .ySt,yEd: y start and end for analysis ROI%   .xSt,xEd: x start and end for analysis ROI% bgImgC: back ground image cell% lPass: parameter for low pass filter%   1: factor%   2: pit size%   3: minimum counts%   4: iteration% vgntC: vignette compensation cell% c2c: count to charge factor [fC/count]%% Written by Kei Nakamura% 2018/2/22 ver.1: created%%% main body missI = 0;  % missing image indicatorimgC = cell(1,4);for i=1:4        %% read image    imgPath = [imgPathC{i},sNmbS,'.png'];   % complete file path       if exist(imgPath,'file')        [imgR,~] = f12bitPngOpnV04(imgPath);     % download image        img = imgR(camClb(i).ySt:camClb(i).yEd,camClb(i).xSt:camClb(i).xEd); % ROI    else        missI = i;    end        % % bg img    % subplot(3,4,i)    % pcolor(log10(bgImgC{i}))    % shading interp    % colorbar    % title('bg')    %     % % raw img    % subplot(3,4,i+4)    % pcolor(log10(imgR))    % shading interp    % colorbar    % title('raw')        %% process     img(:,:) = fTrexTonyBgV01(img,bgImgC{i});   % back ground subtraction      [img(:,:),~] = fXrayOutV10(img,lPass);  % low pass filter    img(:,:) = img.*vgntC{i};              % vignette compensation    pvtY = camClb(i).yCntr - camClb(i).ySt;    % pivot y    img(:,:) = fImageRotV02(img,camClb(i).rot,[0.5*camClb(i).width,pvtY]); % rotate image    %sum(sum(img))    %% incident angle compensation    [szy,~] = size(img);    % get size for mesh grid    [angl,~] = meshgrid(x(i).incAgl,1:szy); % incident angle mesh    angl(:,:) = cos(pi*angl/180); % cos(incAgl)    img(:,:) = c2c(i)*img.*angl;   % compensation and charge conversion    %sum(sum(img))     %% put into a cell    imgC{i} = img;        % check image    % subplot(3,4,i+8)    % pcolor(log10(img))    % shading interp    % colorbar    % title('processed')end%% flip up-down for front window%imgC{1} = flipud(imgC{1}); %imgC{2} = flipud(imgC{2});
